parameters.jsCode:
try {
  // 'Classify Message' now calls the app's centralized /api/internal/n8n/ai/classify
  // endpoint (ai_prompts/classification_prompt.txt schema) instead of OpenAI directly.
  const j0 = $('Classify Message').first().json;
  const input = $('Build Classification Input').first().json;

  if (j0 && j0.code === 'ai_not_configured') {
    return [
      {
        json: {
          intent: 'other',
          urgency: 'medium',
          estimated_value: 0,
          risk_type: 'none',
          risk_score: 0.5,
          missing_fields: [],
          recommended_action: 'request_approval',
          confidence: 0,
          classification_failed: true,
          ai_not_configured: true,
          summary: 'AI classification is not configured - manual review needed',
          conversation_id: input.conversation_id,
          customer_name: input.customer_name,
          customer_email: input.customer_email,
          approval_mode: input.approval_mode,
          lead_id: input.lead_id || '',
        },
      },
    ];
  }

  const c = j0 && j0.classification;
  if (!c) {
    return [
      {
        json: {
          _error: true,
          _errorMessage:
            (j0 && j0.error && (j0.error.message || j0.error)) || 'AI classification failed or returned empty',
          _errorNode: 'ClassifyMessage',
          _timestamp: new Date().toISOString(),
        },
      },
    ];
  }

  // Map the canonical classify schema (intent_type/urgency/revenue_risk/lead_score/...) onto
  // WF2's existing lead fields (intent/estimated_value/risk_type/risk_score/recommended_action)
  // so Create Lead / Route by Action / Trigger WF3 keep working unchanged. estimated_value has
  // no canonical equivalent (the shared prompt does not estimate a currency amount) and is 0
  // until a dedicated field is added - this is a known behavior change from the old ad-hoc prompt.
  const INTENT_MAP = {
    pricing_question: 'pricing_request',
    booking_request: 'booking_request',
    complaint: 'complaint',
    churn_risk: 'complaint',
    support_issue: 'support',
    follow_up: 'proposal_followup',
    new_lead: 'other',
    general: 'other',
  };
  const RISK_SCORE_MAP = { low: 0.2, medium: 0.5, high: 0.8, critical: 0.95 };

  const intent = INTENT_MAP[c.intent_type] || 'other';
  const urgency = c.urgency === 'critical' ? 'high' : c.urgency || 'medium';
  const riskScore = RISK_SCORE_MAP[c.revenue_risk] ?? 0.5;
  const riskType =
    c.intent_type === 'churn_risk' || c.revenue_risk === 'high' || c.revenue_risk === 'critical'
      ? 'churn_risk'
      : c.revenue_risk === 'medium'
        ? 'lead_may_go_cold'
        : 'none';
  const recommendedAction = c.needs_human_approval ? 'request_approval' : 'draft_reply';

  return [
    {
      json: {
        intent,
        urgency,
        estimated_value: 0,
        risk_type: riskType,
        risk_score: riskScore,
        missing_fields: [],
        recommended_action: recommendedAction,
        confidence: Number(c.confidence) || 0,
        summary: c.summary || '',
        classification_failed: false,
        conversation_id: input.conversation_id,
        customer_name: input.customer_name,
        customer_email: input.customer_email,
        approval_mode: input.approval_mode,
        lead_id: input.lead_id || '',
      },
    },
  ];
} catch (error) {
  return [
    {
      json: {
        _error: true,
        _errorMessage: error.message,
        _errorNode: 'ParseAIResponse',
        _timestamp: new Date().toISOString(),
      },
    },
  ];
}

try {
  const parsed = $('Parse AI Response').first().json;
  const current = $input.first().json;
  const responseBody = current.body || current;
  let row = Array.isArray(responseBody) ? responseBody[0] : responseBody;
  if (row && row.data && typeof row.data === 'object') row = row.data;
  const leadId = parsed.lead_id || (row && row.id) || current.id || '';

  return [
    {
      json: {
        ...parsed,
        lead_id: leadId,
        lead_row: row || null,
      },
    },
  ];
} catch (error) {
  return [
    {
      json: {
        _error: true,
        _errorMessage: error.message,
        _errorNode: 'NormalizeLeadResult',
        _timestamp: new Date().toISOString(),
      },
    },
  ];
}

